{"type": "email", "id": "email_001", "subject": "Weekly Sales Team Meeting", "from": "liam.patel@mediconnsolutions.com", "from_name": "Liam Patel", "to": ["michelle.ross@mediconnsolutions.com", "daniel.kim@mediconnsolutions.com", "sarah.hughes@mediconnsolutions.com", "michael.lee@mediconnsolutions.com", "emma.johnson@mediconnsolutions.com"], "cc": [], "date": "2025-03-05 10:00:00", "body": "Hello team,

